#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int findMissingNumber(vector<int>& nums) {
        unordered_set<int> num_set(nums.begin(), nums.end());
        for (int i = 0; i <= 10000; i++) {
            if (num_set.find(i) == num_set.end()) {
                return i;
            }
        }
        return -1;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    Solution sol;
    int ans = sol.findMissingNumber(nums);
    cout << ans << '\n';
    return 0;
}
